INSERT INTO public.standard_groups_resource (created_at, name, short_name, description, points, pass_points, active, id, generated, mcp) VALUES ('2025-08-12T12:52:09.663779+00:00', 'Adapts approach to individual student needs', 'Adaptability', 'Flexibility in teaching approach based on student personality and needs.', 5, 4, true, '019b3be4-3cc0-71ef-a1d4-b3d0deac7ead', false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standard_groups_resource (created_at, name, short_name, description, points, pass_points, active, id, generated, mcp) VALUES ('2025-08-12T12:52:09.663779+00:00', 'Facilitates student-driven learning', 'Active Listening', 'Ability to guide students to discover solutions independently through questioning.', 5, 4, true, '019b3be4-3cc0-72ae-8181-dc2d5f6cee0d', false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standard_groups_resource (created_at, name, short_name, description, points, pass_points, active, id, generated, mcp) VALUES ('2025-08-12T12:52:09.663779+00:00', 'Demonstrates understanding of core concepts', 'Content Mastery', 'Knowledge and articulation of core goals and learning outcomes.', 5, 4, true, '019b3be4-3cc0-72bb-aef9-c6d1c0a794d5', false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standard_groups_resource (created_at, name, short_name, description, points, pass_points, active, id, generated, mcp) VALUES ('2025-08-12T12:52:09.663779+00:00', 'Interpersonal communication and professionalism', 'Communication', 'Flexibility in teaching approach based on student personality and needs.', 5, 4, true, '019b3be4-3cc0-72c6-8b83-ba801e217cbf', false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standard_groups_resource (created_at, name, short_name, description, points, pass_points, active, id, generated, mcp) VALUES ('2025-08-12T12:52:09.663779+00:00', 'Manages session time effectively', 'Time Management', 'Efficient use of session time and respect for scheduling.', 5, 4, true, '019b3be4-3cc0-72d3-9909-6eaf43e3d094', false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Excellent', 'Consistently employs open-ended questions that empower students to discover solutions independently.', 5, '019b3be4-3ccb-708d-80e7-51b691b555a7', '019b3be4-3cc0-72ae-8181-dc2d5f6cee0d', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Good', 'Regularly uses guided questioning, encouraging student reasoning with occasional prompts.', 4, '019b3be4-3ccb-79f6-94ba-79f5d64f4da5', '019b3be4-3cc0-72ae-8181-dc2d5f6cee0d', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Acceptable', 'Occasionally guides students with questions but sometimes provides direct answers.', 3, '019b3be4-3ccb-7a0a-aa26-89b6b78b15c8', '019b3be4-3cc0-72ae-8181-dc2d5f6cee0d', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Marginal', 'Rarely uses questioning techniques, often resorting to hints or partial solutions.', 2, '019b3be4-3ccb-7a13-b68a-7356120e342d', '019b3be4-3cc0-72ae-8181-dc2d5f6cee0d', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Poor', 'Directly provided the answer.', 1, '019b3be4-3ccb-7c83-bf5d-78130778498f', '019b3be4-3cc0-72ae-8181-dc2d5f6cee0d', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Excellent', 'Begins and concludes sessions within scheduled times, maximizing productivity and respecting student availability.', 5, '019b3be4-3ccb-7c8d-9223-a4036e26ca5c', '019b3be4-3cc0-72d3-9909-6eaf43e3d094', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Good', 'Generally adheres to time allocations with minor deviations that do not impact session quality.', 4, '019b3be4-3ccb-7c9a-a648-3653254dd832', '019b3be4-3cc0-72d3-9909-6eaf43e3d094', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Acceptable', 'Sometimes exceeds or finishes early, slightly affecting pacing yet maintaining core engagement.', 3, '019b3be4-3ccb-7ca6-9eae-11efeb2889ef', '019b3be4-3cc0-72d3-9909-6eaf43e3d094', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Marginal', 'Frequently mismanages time, leading to rushed explanations or unnecessary prolongation.', 2, '019b3be4-3ccb-7cb6-9c52-3c1a6049430f', '019b3be4-3cc0-72d3-9909-6eaf43e3d094', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Poor', 'Ended the conversation really early, or made it last longer than needed.', 1, '019b3be4-3ccb-7cc1-ac03-582413caba8c', '019b3be4-3cc0-72d3-9909-6eaf43e3d094', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Excellent', 'Perfectly adapts approach to diverse student emotional and attitude types.', 5, '019b3be4-3ccb-7ccd-b136-489245b9d44e', '019b3be4-3cc0-71ef-a1d4-b3d0deac7ead', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Good', 'Mostly seamlessly adjusted communication and teaching style to effectively engage students across a wide range of emotions.', 4, '019b3be4-3ccb-7cdd-8d41-28b981adbb2b', '019b3be4-3cc0-71ef-a1d4-b3d0deac7ead', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Acceptable', 'Demonstrates thoughtful adjustments to support most student types, maintaining a supportive and responsive demeanor.', 3, '019b3be4-3ccb-7ceb-86fc-0faa43b38349', '019b3be4-3cc0-71ef-a1d4-b3d0deac7ead', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Marginal', 'Shows minimal ability to adjust to varied student behaviors, occasionally missing cues or responding inappropriately.', 2, '019b3be4-3ccb-7cf4-bdf1-adc4bbac9025', '019b3be4-3cc0-71ef-a1d4-b3d0deac7ead', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Poor', 'Fails to adapt to different student types, responding uniformly without consideration of individual emotional or behavioral needs.', 1, '019b3be4-3ccb-7cfe-91dc-4c083ceb6478', '019b3be4-3cc0-71ef-a1d4-b3d0deac7ead', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Excellent', 'Consistently communicates with clarity and professionalism. Follows up when needed and maintains respectful boundaries in all interactions.', 5, '019b3be4-3ccb-7d07-bc1f-8bbc88df7d59', '019b3be4-3cc0-72c6-8b83-ba801e217cbf', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Good', 'Communicates respectfully and clearly with minor lapses in tone or timing. Upholds professional standards.', 4, '019b3be4-3ccb-7d11-b870-8930594fec0d', '019b3be4-3cc0-72c6-8b83-ba801e217cbf', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Acceptable', 'Communication is mostly appropriate but may occasionally be abrupt, or overly casual.', 3, '019b3be4-3ccb-7d18-a14f-f68e642a3cfd', '019b3be4-3cc0-72c6-8b83-ba801e217cbf', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Marginal', 'Shows limited awareness of tone or affect. May interrupt, dismiss student concerns, or respond in ways that feel cold or reactive.', 2, '019b3be4-3ccb-7d21-9879-c7f0a428f46d', '019b3be4-3cc0-72c6-8b83-ba801e217cbf', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Poor', 'Demonstrates inappropriate or unprofessional behavior (e.g., sarcastic tone, dismissive responses, or failure to maintain respectful interaction).', 1, '019b3be4-3ccb-7d2b-a60d-6347af838659', '019b3be4-3cc0-72c6-8b83-ba801e217cbf', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Excellent', 'States core concepts clearly; explains in clear, bite-sized steps; uses analogies/visuals to clarify when needed; consistently checks understanding.', 5, '019b3be4-3ccb-7d32-ab5d-00b1134aa994', '019b3be4-3cc0-72bb-aef9-c6d1c0a794d5', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Good', 'Explains core concepts accurately and relates examples to key learning outcomes. Generally provides step-by-step reasoning and occasionally checks for student comprehension.', 4, '019b3be4-3ccb-7d3b-97df-8c24df676cf2', '019b3be4-3cc0-72bb-aef9-c6d1c0a794d5', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Acceptable', 'Provides a basic overview of concepts but with occasional inaccuracies or lack of depth. Some explanations may feel rushed or cognitively dense.', 3, '019b3be4-3ccc-73e6-9e54-e88b8c142cb2', '019b3be4-3cc0-72bb-aef9-c6d1c0a794d5', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Marginal', 'Demonstrates limited awareness of core concepts and offers explanations with minor errors. Explanations frequently rushed, dense, or skip logical steps; seldom checks comprehension.', 2, '019b3be4-3ccc-73f7-965d-791773e2baba', '019b3be4-3cc0-72bb-aef9-c6d1c0a794d5', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2025-08-12T12:52:09.668836+00:00', 'Poor', 'Misstates or omits concepts; dumps information or skips logic, confusing students; no comprehension checks and may rely on students for content.', 1, '019b3be4-3ccc-7402-a396-24de5a95f832', '019b3be4-3cc0-72bb-aef9-c6d1c0a794d5', true, false, false) ON CONFLICT (id) DO NOTHING;
